var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"하아……. 하아…….","JPN":"はあ……はあ……","ENG":"Huff... Huff...","TWN":"呼……呼……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"후우. 성가신 놈이었네.","JPN":"ふう。やっかいな相手だったわ。","ENG":"Whew. That was tough.","TWN":"呼～那傢伙真不好對付！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"잘했어. 그래도 둘이라서 좀 더 쉽게 해치웠네.","JPN":"よくやったわ。二人で対処できたおかげで、思ってたより簡単に倒せたわね。","ENG":"Good job. Two heads are better than one, right?","TWN":"幹得好！二對一還是比較省力點。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……내 의뢰는 망하고 말이야.","JPN":"……俺の依頼は失敗になったけどな。","ENG":"And there goes my payment.","TWN":"……我的委託完蛋了。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"뭐가 걱정이야. 사지 멀쩡한 젊은 녀석이.","JPN":"心配ないわ。元気だし、若いし、まだ稼げるチャンスはあるわよ。","ENG":"Don't worry. You're young and strong.","TWN":"擔心什麼，你好手好腳的，還怕賺不到錢嗎？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"네가 헴스워스 영감 성질머리를 몰라서 그래.","JPN":"あんたはヘムズワース爺の性格を知らないからそう言えるんだ。","ENG":"You don't know Helmsworth.","TWN":"你不知道漢姆沃斯的個性啦！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이번에도 외상 못 갚으면 새로 커스텀한 총의 실험체가 될 거라고.","JPN":"今回も返済できなかったら、新作のカスタムガンの実験体にされちまう。","ENG":"If I don't pay my tab this time, he'll test his new custom guns on me.","TWN":"這次再不還錢的話，我會成為他的槍下魂啦！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"저런, 안 본 사이 엄살이 늘었네.","JPN":"あらら、見ないうちに臆病になっちゃったのね。","ENG":"Oh, you've become a coward in the short time I was away.","TWN":"哇，才一陣子不見，講話變這麼浮誇！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"뭐야? 벌써 괴도가 나타난 거야?!","JPN":"なんだ？　もう怪盗が現れたのか！？","ENG":"What? Was the Thief already here?","TWN":"什麼嘛～怪盜已經出現過啦？！"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L14_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"설마 혼자 잡은 건 아니겠지?","JPN":"まさか一人で捕まえたんじゃないよな？","ENG":"You didn't catch him by yourself, did you?","TWN":"你該不會自己都處理完了吧？"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L15_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"우리도 한 몫 한 걸로 쳐줘야 한다?","JPN":"もちろん、俺らも一緒に捕まえたことにしてくれるよな？","ENG":"Because we did our bit, you know.","TWN":"我們要假裝也有參一腳嗎？"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L18_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……어디 갔나 했더니 이제야 왔군.","JPN":"……どこへ消えたのかと思っていたら、ようやく来たな。","ENG":"Finally, you're back.","TWN":"……我還想說你們人咧？結果都處理完才出現。"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"……어라?","JPN":"……あれ？","ENG":"Err?","TWN":"……哦？"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"혹시…… 이 괴물이 괴도 르블랑인가?","JPN":"もしかして……この化け物が怪盗ルブランか？","ENG":"Wait... Is this monster LeBlanc the Thief?","TWN":"這個怪物……就是怪盜布勒朗？"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"크흠, 흠. 확실히 그림자도 보기 싫어지는 생김새긴 한데.","JPN":"ふむ、ふむ。確かに影も見たくない顔立ちではあるな。","ENG":"Kahem, kahem. I definitely wouldn't have wanted to see it or its shadow.","TWN":"咳咳，長得確實不太想看到他的人影。"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"이런. 내 샷건, <color=#ffd34c>그란투리스모</color>와 맞붙기엔 너무 연약했나 보군.","JPN":"やれやれ。俺のショットガン<color=#ffd34c>グランドツアー</color>と戦うには弱すぎたようだな。","ENG":"Too bad It must have been too weak to face my shotgun, <color=#ffd34c>Gran Turismo</color>.","TWN":"我看這傢伙似乎不是我的霰彈槍 <color=#ffd34c>格蘭多·里斯莫</color>的對手！"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……그럴 리가 있겠냐.","JPN":"……そんなわけないだろ。","ENG":"Well, that's ridiculous.","TWN":"……沒這種事啦！"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L27_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"친구들 안녕? 또 보네?","JPN":"ハァイ、みんな。また会えたわね？","ENG":"Hey, fellas. We meet again.","TWN":"嗨～大家好，又見面囉～"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"뭐야? 저 여자가 왜 여기 있어?!","JPN":"おい、あの女がなんでここにいるんだ！？","ENG":"Huh? What the hell are you doing here?","TWN":"搞什麼？這女的怎麼會在這裡？！"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"덕분에 우리 사무소가 얼마나 궁핍해졌는지 알아?!","JPN":"お前のせいでうちの事務所がどんだけ苦労してるか、わかってんのか！？","ENG":"Do you know how much damage you've caused to our business?","TWN":"她不知道她把我們的事務所搞到快破產嗎？！"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"우리가 가도 물 한 모금 못 얻어 마신다고!","JPN":"俺らに水一杯もタダで飲ませてくれないんだぞ！","ENG":"John can't even offer us a glass of water when we're at the office!","TWN":"我們連口水都要不到！"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"그건 원래부터 그랬어.","JPN":"それは元からそうだったけどな。","ENG":"He never did before.","TWN":"公司本來就不給水喝啦！"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"아. 그랬지, 참.","JPN":"あ、そうだった。","ENG":"Ah, you're right.","TWN":"對吼，說得也是。"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"아무튼 우리 돈 내놔!","JPN":"とにかく、金を返せ！","ENG":"Anyways, give us our money back!","TWN":"總之把我們的錢還來啦！"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"미안. 다 써 버렸어.","JPN":"ごめんね、全部使っちゃったの。","ENG":"Sorry. I spent it all.","TWN":"不好意思，花光光了。"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그게 웃는 얼굴로 할 소리냐?!","JPN":"そんな笑顔で言えることか！？","ENG":"You shouldn't be smiling when you say that!","TWN":"你還好意思講？！"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"그, 그 거금을 다 써 버렸다고?","JPN":"あ、あの大金を使い果たしただと？","ENG":"B-but there was so much money. How could you spend it all?","TWN":"那…那麼大筆錢都花光了？"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"어쩌지? 파산하기 전에 다른 사무소로 이직해야 하나?","JPN":"どうする？　ガチで破産する前に他の事務所に移籍したほうがよさげじゃないか？","ENG":"What do we do? Should we move to a different agency before John's shuts down?","TWN":"現在怎麼辦？在事務所倒閉前趕快跳槽嗎？"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"크흑……! 은퇴 후에 펼쳐질 내 화려한 인생이……!","JPN":"くう……！　引退後に繰り広げられる予定だった俺の華麗な人生が……！","ENG":"*Sniffle...* My spectacular post-retirement life is gone!","TWN":"可惡……！我的退休生活……！"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"너무 걱정하지 마. 이 여자가 괴도…….","JPN":"あまり心配するな。この女が怪盗……","ENG":"Don't worry too much. She's the Thief—","TWN":"大家別愁眉苦臉的，這女的就是怪盜……"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"에이, 농담이지. 그 많은 돈을 어떻게 나 혼자 다 썼겠어.","JPN":"ふふ、冗談よ。あんな大金をアタシ一人で使い切れるわけないでしょ。","ENG":"Come on, I was just joking. There's no way I could spend so much money by myself.","TWN":"哎唷～開玩笑的啦，那麼多錢，我一個人怎麼可能花得完？"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L50_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……후우.","JPN":"ふう……","ENG":"Whew.","TWN":"……呼～"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"좋아. 의뢰인에게 걸려서 평생 감옥살이 하기 싫으면 보상금만 되돌려 놓기나 해.","JPN":"よし、こっちの依頼主に捕まって一生刑務所暮らしをしたくなければ、報奨金を返してくれ。","ENG":"Alright. Just give us the money back before my client catches you and throws you into prison.","TWN":"很好，你如果不想被委託人送去吃牢飯，就乖乖把獎金吐出來！"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그런데 의뢰인은 잘 있던가?","JPN":"ところで、依頼主はどうだった？","ENG":"By the way, how's our client doing?","TWN":"不過不知道委託人還好嗎？"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"저 괴물을 치우기 전까지는 얌전히 있으면 좋겠는데.","JPN":"あの化物を片付けるまでは、大人しく待機していてほしいが。","ENG":"I hope he'll stay where he is until we get rid of that monster.","TWN":"希望他有乖乖待著。"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"어? 의뢰인?","JPN":"ん？　依頼主？","ENG":"Huh? Client?","TWN":"嗯？委託人？"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_RICH","text":{"KOREA":"벌써 괴도를 잡았나? 역시 실력이 좋다더니…… ","JPN":"もう怪盗を捕まえたのか？　さすが実力があると聞いていただけのことは……","ENG":"Did you already catch the Thief? You're as good as I heard you were. ","TWN":"你們抓到怪盜了嗎？能力果然不錯…… "},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_RICH","text":{"KOREA":"으응?!","JPN":"んん！？","ENG":"Mm?","TWN":"嗯？！"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_RICH","text":{"KOREA":"이게…… 이게…… 이게 다 무슨……!","JPN":"こ……これは……いったいどういう……！","ENG":"This is... No... How...","TWN":"這……這是……怎麼會……！"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"의뢰인이라면 우리랑 같이 왔는데?","JPN":"依頼主なら俺らと一緒に来たぞ？","ENG":"He came with us.","TWN":"委託人和我們一起過來咧？"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그걸 왜 이제야 말해!","JPN":"なんでそれを今言うんだよ！","ENG":"Why didn't you say that earlier?","TWN":"你怎麼不早說！！"},"stage":{"bg":"HALL","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_RICH","text":{"KOREA":"내…… 내 귀염둥이가……!","JPN":"う……うちのかわいこちゃんが……！","ENG":"My... My cutie!","TWN":"我的……我的小可愛……！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"저 널브러져 있는 침식체 말이야?","JPN":"あのボロ雑巾みたいになっている侵食体のことか？","ENG":"Are you talking about that C.O. lying over there?","TWN":"你是叫那個躺在地上的侵蝕體嗎？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"살아 있을 때도 그렇게 귀엽진 않았을 것 같은데.","JPN":"生きている時もそこまで可愛かったとは思えんが。","ENG":"I don't think it would have looked cute even when it was alive.","TWN":"他活著的時候應該也稱不上可愛吧？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"야, 야. 눈치 챙겨.","JPN":"おいおい。空気を読め。","ENG":"Hey, hey. Just keep your mouth shut.","TWN":"喂喂！好好說話！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"이 참에 침식체 말고 앞날 창창한 용병 한 명 키우는 건 어떠십니까?","JPN":"この際、侵食体ではなく将来有望な傭兵を1人飼うのはいかがでしょうか？","ENG":"If you're looking for a good companion, how about a promising mercenary instead of a C.O.?","TWN":"我看不如這樣，別養什麼侵蝕體，趁這個機會改養一隻前途無量的傭兵如何？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"눈치 챙기라고!","JPN":"空気読めって！","ENG":"I said, shut up!","TWN":"你少在那邊白目！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_RICH","text":{"KOREA":"아…… 아아…….","JPN":"あ……ああ……","ENG":"Ah... Aaah...","TWN":"嗚……嗚嗚嗚……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_RICH","text":{"KOREA":"어흑흑. 귀염둥아…… 내 귀염둥이야아…….","JPN":"ぐううぅ、うちの子が……可愛い可愛いうちの子が……","ENG":"Boohoo! Cutie... My cutieeeeehhh!","TWN":"嗚嗚嗚，小可愛……我的小可愛……"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_RICH","text":{"KOREA":"누구야! 누가 이런 추악하고 잔인무도한 짓을!!","JPN":"誰だ！　誰がこんな残酷非道なことを！！","ENG":"Who did this? Who murdered my lovely pet?","TWN":"到底是誰！是誰這麼殘忍！"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"크흠.","JPN":"こほん。","ENG":"Kahem.","TWN":"咳咳。"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"뭐, 뭐야?","JPN":"な、何だ？","ENG":"W-what?","TWN":"呃…幹嘛？"},"stage":{"bg":"HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_RICH","text":{"KOREA":"네 놈이냐!!","JPN":"お前か！！","ENG":"Was it you?","TWN":"是你嗎！"},"stage":{"bg":"HALL","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_RICH","text":{"KOREA":"저, 저 놈 잡아!","JPN":"みんな、あいつ捕まえろ！","ENG":"G-get him!","TWN":"把他給我抓起來！"},"stage":{"bg":"HALL","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_RICH","text":{"KOREA":"의뢰비의 두 배, 아니 세 배를 주겠다!!","JPN":"依頼費の二倍、いや三倍をやる！！","ENG":"I'll pay you twice—no, three times—the money I promised!","TWN":"我願意出2倍…不，是3倍的委託費！！"},"stage":{"bg":"HALL","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……말도 없이 처리한 건 사과하지.","JPN":"……断りも入れずに処理したのは謝るよ。","ENG":"I'm sorry I had to take care of your pet without consulting you first.","TWN":"……沒先跟你說一聲就處理掉他，是我的不對。"},"stage":{"bg":"HALL","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"하지만 부탁할 친구들을 잘못 골랐어. 저 녀석들이 설마 날…….","JPN":"しかし、頼む相手を間違えている。まさかあいつらが俺を……","ENG":"But you've chosen the wrong people to ask. They're my friends—","TWN":"但是你找錯人了啦，這些傢伙怎麼可能……"},"stage":{"bg":"HALL","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"맡겨 주십쇼, 어르신. 델타 세븐이 감탄하고 안토노프 중장님이 뒤집어졌던 압도적인 화력을 보여 드리겠습니다.","JPN":"任せてください、お客様。デルタセブンが感嘆し、あのアントノフ中将がたまげた圧倒的な火力をお見せしますぜ。","ENG":"Count on us, sir. I'll show you the firepower that Delta Seven and Lieutenant General Antonov admired.","TWN":"交給我吧！我會讓您瞧瞧，讓第七三角洲部隊嘖嘖稱奇，而且力抗安東諾夫中將的強大火力！"},"stage":{"bg":"HALL","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L42_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"모두를 공포에 몰아 넣었던 리플레이서 퀸을 일격에 격추한 이 제리의 활약도 잊지 말라고.","JPN":"皆を恐怖に陥れたリプレイサー・クイーンを一撃で撃墜したこのジェリーの活躍も忘れないでくれよ。","ENG":"Don't forget I, Jerry, brought down the dreadful Replacer Queen with a single shot.","TWN":"別忘記，是誰一擊就擊落讓大家陷入恐懼的克隆·女皇？就是我傑瑞！"},"stage":{"bg":"HALL","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L43_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"하하, 궁지에 몰린 뉴 오하이오의 충각 공격에서 모두를 지켜냈던 이 몸을 잊진 않았겠지?","JPN":"ハハ、窮地に追い込まれたニューオハイオの衝角攻撃で皆を守り抜いたこの俺を忘れてはいないだろ？","ENG":"Hah hah. It's widely known that I, Tommy, protected everyone against the New Ohio's ram attack.","TWN":"哈哈！沒忘記我吧？我可是將大家從新俄亥俄的攻擊中拯救出來呢！"},"stage":{"bg":"HALL","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L45_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이, 이봐, 다들 정말 날 잡으려는 건 아니지?","JPN":"お、おい、本気で俺を捕まえようとしてるわけじゃないよな？","ENG":"H-hey, you're not really going to attack me, are you?","TWN":"喂！你們不會真的是要抓我吧？"},"stage":{"bg":"HALL","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이봐, 공범! 가만히 있지 말고 뭐라도 좀 해 봐!","JPN":"おい、共犯者！　黙ってないでなんとか言え！","ENG":"Hey, partner in crime! Do something!","TWN":"喂，共犯！快幫我說句話啊！"},"stage":{"bg":"HALL","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"떨거지들! 뒤는 내가 맡고 있을게!","JPN":"そこのトリオ！　後ろはアタシが塞ぐわよ！","ENG":"Losers! I'll cover the behind!","TWN":"大夥兒！後面交給我！"},"stage":{"bg":"HALL","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"TOMY_MASON_SUPPLEMENT_NULL","text":{"KOREA":"우오오오오! 가자, 짜식들아!!","JPN":"うおおお！　全員、突撃ぃぃぃーっ！","ENG":"Oooooh! Let's do this, guys!","TWN":"喔喔喔喔！大家上！"},"stage":{"bg":"HALL","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_SUPPLEMENT_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"야, 이 배신자들아!","JPN":"おい、この裏切り者ども！","ENG":"You traitors!","TWN":"可惡，你們這些叛徒！"},"stage":{"bg":"HALL","bgm":"BATTLE_PVP_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};